func scanTDSnapshots(rows *sql.Rows) ([]TDSnapshot, error) {
	snaps := make([]TDSnapshot, 0)
	for rows.Next() {
		var (
			eventID             sql.NullString
			getInPrice          sql.NullFloat64
			maxPrice            sql.NullFloat64
			numberOfListings    sql.NullInt64
			forecastValue       sql.NullFloat64
			forecastAvailable   sql.NullInt64
			threeDayChangePct   sql.NullFloat64
			priceTrendDirection sql.NullString
			capturedAt          sql.NullString
		)
		if err := rows.Scan(
			&eventID,
			&getInPrice,
			&maxPrice,
			&numberOfListings,
			&forecastValue,
			&forecastAvailable,
			&threeDayChangePct,
			&priceTrendDirection,
			&capturedAt,
		); err != nil {
			return nil, err
		}
		snaps = append(snaps, TDSnapshot{
			EventID:             eventID.String,
			GetInPrice:          getInPrice.Float64,
			MaxPrice:            maxPrice.Float64,
			NumberOfListings:    int(numberOfListings.Int64),
			ForecastValue:       forecastValue.Float64,
			ForecastAvailable:   forecastAvailable.Int64 != 0,
			ThreeDayChangePct:   threeDayChangePct.Float64,
			PriceTrendDirection: priceTrendDirection.String,
			CapturedAt:          capturedAt.String,
		})
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return snaps, nil
}
